import (
	"container/heap"
)

type Element struct {
	value  int64
	limit  int64
	index  int
}

type MaxHeap []*Element

func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return h[i].value > h[j].value }
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i]; h[i].index = i; h[j].index = j }

func (h *MaxHeap) Push(x interface{}) {
	n := len(*h)
	element := x.(*Element)
	element.index = n
	*h = append(*h, element)
}

func (h *MaxHeap) Pop() interface{} {
	old := *h
	n := len(old)
	element := old[n-1]
	old[n-1] = nil
	element.index = -1
	*h = old[0 : n-1]
	return element
}

func solve(value []int64, limit []int64) int64 {
	n := len(value)
	if n == 0 {
		return 0
	}

	h := make(MaxHeap, 0, n)
	for i := 0; i < n; i++ {
		heap.Push(&h, &Element{value: value[i], limit: limit[i]})
	}

	var res int64
	activeCount := int64(0)

	for h.Len() > 0 {
		element := heap.Pop(&h).(*Element)
		if activeCount < element.limit {
			res += element.value
			activeCount++
			// Now, remove any elements with limit <= activeCount
			temp := make([]*Element, 0)
			for h.Len() > 0 {
				e := heap.Pop(&h).(*Element)
				if e.limit > activeCount {
					temp = append(temp, e)
				}
			}
			// Push back the valid elements
			for _, e := range temp {
				heap.Push(&h, e)
			}
		}
	}

	return res
}
